// Filter approved prospects for email outreach
const items = $input.all();

console.log('📧 Starting Instantly Campaign Automation...');
console.log('Total items received:', items.length);

// Process ALL leads and add approval status
const processed = items.map(item => {
  const data = item.json;

  // Check approval status
  const companyApproved = data['Company Approved'] === 'Yes' || data.company_approved === true;
  const personaApproved = data['Persona Approved'] === 'Yes' || data.persona_approved === true;

  // Check for valid email
  const hasEmail = data['Email Id'] || data.email || data.Email;

  // Determine unapproval reasons
  let reasons = [];
  if (!companyApproved) reasons.push('Company not approved');
  if (!personaApproved) reasons.push('Persona not approved');
  if (!hasEmail) reasons.push('No valid email address');

  const isApproved = companyApproved && personaApproved && hasEmail;

  return {
    ...item,
    json: {
      ...data,
      is_approved: isApproved,
      approval_status: isApproved ? 'Approved' : reasons.join(', '),
      unapproval_reasons: reasons
    }
  };
});

// Filter for approved leads
const approved = processed.filter(item => item.json.is_approved);

console.log('✅ Approved prospects with emails:', approved.length);
console.log('❌ Rejected prospects:', processed.length - approved.length);

if (approved.length === 0) {
  console.log('⚠️ No approved prospects found. Stopping workflow.');
  return [];
}

// Map to clean prospect data
return approved.map(item => {
  const data = item.json;
  return {
    json: {
      // Core fields
      email: data['Email Id'] || data.email || data.Email,
      first_name: data.person_first_name || data['Name']?.split(' ')[0] || data.first_name || '',
      last_name: data['Name']?.split(' ').slice(1).join(' ') || data.person_last_name || data.last_name || '',

      // Company information
      company_name: data['Company Name'] || data.company_name || '',
      company_domain: data['Company Domain'] || data.company_domain || data.website || '',

      // Role and industry
      designation: data['Designation'] || data.person_title || data.title || '',
      industry: data['Company Industry'] || data.company_industry || '',

      // Context for personalization
      tech_stack: data['Company Technologies'] || data.company_technologies || data.technologies || '',
      company_keywords: data['Company Keywords'] || data.company_keywords || data.keywords || '',

      // NEW: Add approval tracking
      is_approved: data.is_approved,
      approval_status: data.approval_status
    }
  };
});

// Show rejected leads with reasons
const items = $input.all();

console.log('🔍 Checking for rejected leads...');

// Filter for rejected leads only
const rejected = items.filter(item => {
  const data = item.json;
  const companyApproved = data['Company Approved'] === 'Yes' || data.company_approved === true;
  const personaApproved = data['Persona Approved'] === 'Yes' || data.persona_approved === true;
  const hasEmail = data['Email Id'] || data.email || data.Email;

  return !(companyApproved && personaApproved && hasEmail);
});

console.log('❌ Total rejected leads:', rejected.length);

if (rejected.length === 0) {
  console.log('✅ All leads were approved!');
  return [];
}

// Format rejected leads with reasons
return rejected.map(item => {
  const data = item.json;

  // Determine reasons
  let reasons = [];
  if (data['Company Approved'] !== 'Yes' && !data.company_approved) {
    reasons.push('Company not approved');
  }
  if (data['Persona Approved'] !== 'Yes' && !data.persona_approved) {
    reasons.push('Persona not approved');
  }
  if (!data['Email Id'] && !data.email && !data.Email) {
    reasons.push('No valid email address');
  }

  return {
    json: {
      lead_name: data['Name'] || 'Unknown',
      email: data['Email Id'] || data.email || data.Email || 'NO EMAIL',
      company: data['Company Name'] || 'Unknown',
      designation: data['Designation'] || data.person_title || 'Unknown',

      // Approval details
      company_approved: data['Company Approved'] || data.company_approved || 'No',
      persona_approved: data['Persona Approved'] || data.persona_approved || 'No',

      // Rejection info
      rejection_reasons: reasons.join(' | '),
      total_reasons: reasons.length,
      status: '❌ REJECTED'
    }
  };
});

return [{
     json: {
       first_name: "{{firstName}}",
       last_name: "{{lastName}}",
       company_name: "{{companyName}}",
       company_domain: "{{website}}",
       designation: "{{designation}}",
       industry: "{{industry}}",
       tech_stack: "{{tech_stack}}",
       company_keywords: "{{company_keywords}}"
     }
   }];

let aiResponse = '';

if (Array.isArray($input.all()) && $input.all()[0]?.json) {
  const firstItem = $input.all()[0].json;

  if (Array.isArray(firstItem) && firstItem[0]?.text) {
    aiResponse = firstItem[0].text;
  } else if (firstItem.text) {
    aiResponse = firstItem.text;
  }
}

if (!aiResponse) {
  throw new Error('No AI response found');
}

const email1Match = aiResponse.match(/EMAIL_1_SUBJECT:\s*(.+?)\s*EMAIL_1_BODY:\s*(.+?)(?=EMAIL_2_SUBJECT|$)/s);
const email2Match = aiResponse.match(/EMAIL_2_SUBJECT:\s*(.+?)\s*EMAIL_2_BODY:\s*(.+?)(?=EMAIL_3_SUBJECT|$)/s);
const email3Match = aiResponse.match(/EMAIL_3_SUBJECT:\s*(.+?)\s*EMAIL_3_BODY:\s*(.+?)$/s);

const email1Subject = email1Match?.[1]?.trim() || '';
let email1Body = email1Match?.[2]?.trim().replace(/---/g, '').trim() || '';

const email2Subject = email2Match?.[1]?.trim() || '';
let email2Body = email2Match?.[2]?.trim().replace(/---/g, '').trim() || '';

const email3Subject = email3Match?.[1]?.trim() || '';
let email3Body = email3Match?.[2]?.trim().replace(/---/g, '').trim() || '';

email1Body = email1Body.replace(/(Hi FIRSTNAME,|Hello FIRSTNAME,)/g, '{{RANDOM | Hi {{firstName}}, | Hello {{firstName}},}}');
email2Body = email2Body.replace(/(Hi FIRSTNAME,|Hello FIRSTNAME,)/g, '{{RANDOM | Hi {{firstName}}, | Hello {{firstName}},}}');
email3Body = email3Body.replace(/(Hi FIRSTNAME,|Hello FIRSTNAME,)/g, '{{RANDOM | Hi {{firstName}}, | Hello {{firstName}},}}');

email1Body = email1Body.replace(/COMPANYNAME/g, '{{companyName}}');
email2Body = email2Body.replace(/COMPANYNAME/g, '{{companyName}}');
email3Body = email3Body.replace(/COMPANYNAME/g, '{{companyName}}');

email1Body = email1Body.replace(/Best,/g, '{{RANDOM | Best, | Regards, | Sincerely, }}');
email2Body = email2Body.replace(/Regards,/g, '{{RANDOM | Best, | Regards, | Sincerely, }}');
email3Body = email3Body.replace(/Sincerely,/g, '{{RANDOM | Best, | Regards, | Sincerely, }}');

// Wrap paragraphs in <p> tags
function wrapParagraphs(text) {
  const paragraphs = text.split('\n\n');
  return paragraphs.map(p => `<p>${p.replace(/\n/g, '<br>')}</p>`).join('');
}

email1Body = wrapParagraphs(email1Body);
email2Body = wrapParagraphs(email2Body);
email3Body = wrapParagraphs(email3Body);

return { 
  json: {
    email_1_subject: email1Subject,
    email_1_body: email1Body,
    email_2_subject: email2Subject,
    email_2_body: email2Body,
    email_3_subject: email3Subject,
    email_3_body: email3Body
  }
};
